function slugify(str) {
  return String(str)
    .toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '') // strip accents
    .replace(/&/g, 'and')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
}

/** Resolve a team name (from the API, DB, or seed data) to a local static logo path. */
export function getTeamLogo(name) {
  if (!name) return null
  const slug = slugify(name)
  if (TEAM_LOGOS[slug]) return TEAM_LOGOS[slug]
  const alias = TEAM_ALIASES[name.toLowerCase().trim()] || TEAM_ALIASES[slug]
  if (alias && TEAM_LOGOS[alias]) return TEAM_LOGOS[alias]
  return null
}

/** Resolve a competition/league by slug (preferred) or display name. */
export function getCompetitionLogo(nameOrSlug) {
  if (!nameOrSlug) return null
  const slug = slugify(nameOrSlug)
  if (COMPETITION_LOGOS[slug]) return COMPETITION_LOGOS[slug]
  // common display-name fallbacks
  const NAME_TO_SLUG = {
    'premier-league': 'premier-league',
    'english-premier-league': 'premier-league',
    'efl-championship': 'championship',
    'uefa-champions-league': 'champions-league',
    'uefa-europa-league': 'europa-league',
    'uefa-europa-conference-league': 'conference-league',
    'emirates-fa-cup': 'fa-cup',
    'fa-cup': 'fa-cup',
    'carabao-cup': 'efl-cup',
    'league-cup': 'efl-cup',
    'tennis': 'atp-tour',
    'atp': 'atp-tour',
  }
  if (NAME_TO_SLUG[slug] && COMPETITION_LOGOS[NAME_TO_SLUG[slug]]) return COMPETITION_LOGOS[NAME_TO_SLUG[slug]]
  return null
}

/** Resolve a country name to its flag. */
export function getCountryFlag(country) {
  if (!country) return null
  const slug = slugify(country)
  const COUNTRY_ALIASES = {
    'usa': 'united-states', 'united-states-of-america': 'united-states',
    'uk': 'england', 'great-britain': 'england',
    'south-korea': 'south-korea', 'korea-republic': 'south-korea',
    'ivory-coast': 'ivory-coast', "cote-d-ivoire": 'ivory-coast',
  }
  const key = COUNTRY_ALIASES[slug] || slug
  return FLAG_LOGOS[key] || null
}